module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
)(
    input wclk,
    input wenc,
    input [$clog2(DEPTH)-1:0] wrptr,
    input [$clog2(DEPTH)-1:0] rdptr,
    input [WIDTH-1:0] din,
    output [WIDTH-1:0] dout
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [DEPTH-1:0] full;
reg [DEPTH-1:0] empty;

always @(posedge wclk) begin
    if (wenc && !full[wrptr]) begin
        ram[wrptr] <= din;
        full[wrptr] <= 1'b1;
        empty[wrptr] <= 1'b0;
    end
end

assign dout = ram[rdptr];

endmodule
